// src/pages/Login.jsx

import { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

export default function Login() {

  const nav = useNavigate();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("customer");

  const loginUser = async (e) => {

    e.preventDefault();

    try {

      const res = await axios.post(
        "http://localhost:5000/api/auth/login",
        {
          email,
          password,
          role
        }
      );

      localStorage.setItem(
        "user",
        JSON.stringify(res.data.user)
      );

      if (role === "customer") {

        nav("/customer-dashboard");

      } else {

        nav("/labour-dashboard");

      }

    } catch (err) {

      alert("Invalid Credentials");

    }
  };

  return (

    <div style={styles.page}>

      {/* BACKGROUND SHAPES */}

      <div style={styles.circle1}></div>
      <div style={styles.circle2}></div>
      <div style={styles.circle3}></div>

      {/* LOGIN CARD */}

      <div style={styles.card}>

        <div style={styles.logo}>
          D
        </div>

        <h1 style={styles.title}>
          Welcome Back
        </h1>

        <p style={styles.subtitle}>
          Login to continue
        </p>

        <form onSubmit={loginUser}>

          <select
            style={styles.input}
            value={role}
            onChange={(e) =>
              setRole(e.target.value)
            }
          >

            <option value="customer">
              Customer
            </option>

            <option value="labour">
              Labour
            </option>

          </select>

          <input
            type="email"
            placeholder="Email Address"
            style={styles.input}
            value={email}
            onChange={(e) =>
              setEmail(e.target.value)
            }
          />

          <input
            type="password"
            placeholder="Password"
            style={styles.input}
            value={password}
            onChange={(e) =>
              setPassword(e.target.value)
            }
          />

          <button style={styles.button}>
            Login
          </button>

        </form>

        <p style={styles.bottomText}>

          Don't have an account?

          <span
            style={styles.link}
            onClick={() =>
              nav("/register")
            }
          >
            Register
          </span>

        </p>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background:
      "linear-gradient(135deg,#4f46e5,#9333ea,#ec4899)",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    position: "relative",
    overflow: "hidden",
    fontFamily: "Arial"
  },

  /* BACKGROUND CIRCLES */

  circle1: {
    position: "absolute",
    width: "320px",
    height: "320px",
    borderRadius: "50%",
    background: "rgba(255,255,255,0.12)",
    top: "-100px",
    left: "-80px"
  },

  circle2: {
    position: "absolute",
    width: "260px",
    height: "260px",
    borderRadius: "50%",
    background: "rgba(255,255,255,0.12)",
    bottom: "-80px",
    right: "-60px"
  },

  circle3: {
    position: "absolute",
    width: "180px",
    height: "180px",
    borderRadius: "50%",
    background: "rgba(255,255,255,0.08)",
    top: "120px",
    right: "180px"
  },

  /* CARD */

  card: {
    width: "380px",
    background: "rgba(255,255,255,0.16)",
    backdropFilter: "blur(18px)",
    border: "1px solid rgba(255,255,255,0.2)",
    padding: "40px",
    borderRadius: "28px",
    boxShadow:
      "0 20px 50px rgba(0,0,0,0.2)",
    position: "relative",
    zIndex: 2
  },

  logo: {
    width: "65px",
    height: "65px",
    borderRadius: "20px",
    background: "white",
    color: "#7c3aed",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    margin: "0 auto 22px auto",
    fontSize: "28px",
    fontWeight: "bold"
  },

  title: {
    textAlign: "center",
    color: "white",
    margin: 0,
    fontSize: "34px"
  },

  subtitle: {
    textAlign: "center",
    color: "rgba(255,255,255,0.8)",
    marginTop: "8px",
    marginBottom: "32px",
    fontSize: "15px"
  },

  input: {
    width: "100%",
    padding: "15px",
    marginBottom: "18px",
    borderRadius: "14px",
    border: "none",
    background: "rgba(255,255,255,0.2)",
    color: "white",
    fontSize: "14px",
    outline: "none",
    boxSizing: "border-box"
  },

  button: {
    width: "100%",
    padding: "15px",
    border: "none",
    borderRadius: "14px",
    background: "white",
    color: "#7c3aed",
    fontWeight: "bold",
    fontSize: "15px",
    cursor: "pointer",
    marginTop: "6px"
  },

  bottomText: {
    textAlign: "center",
    marginTop: "24px",
    color: "rgba(255,255,255,0.85)",
    fontSize: "14px"
  },

  link: {
    color: "white",
    marginLeft: "6px",
    cursor: "pointer",
    fontWeight: "bold"
  }

};
